-- file: schemas/0200_00_users.sql
-- USERS (profile mirror of auth.users)
create table if not exists public.users (
  id uuid primary key references auth.users(id) on delete cascade,
  display_name text not null,
  role text not null default 'player', -- 'player' | 'admin'
  created_at timestamptz not null default now()
);

-- file: schemas/0200_01_seasons.sql
-- SEASONS
create table if not exists public.seasons (
  id integer generated by default as identity primary key,
  league text not null default 'NFL',
  year int not null
);

-- file: schemas/0200_02_weeks.sql
-- WEEKS
create table if not exists public.weeks (
  id integer generated by default as identity primary key,
  season_id integer not null references public.seasons(id) on delete cascade,
  week_number int not null,
  start_ts timestamptz not null,
  end_ts   timestamptz not null
);

-- file: schemas/0200_03_teams.sql
-- TEAMS
create table if not exists public.teams (
  id integer generated by default as identity primary key,
  league text not null default 'NFL',
  external_key text unique, -- e.g., 'PHI'
  name text not null,
  short_name text not null
);

-- file: schemas/0200_04_games.sql
-- GAMES
create table if not exists public.games (
  id uuid primary key default gen_random_uuid(),
  week_id integer not null references public.weeks(id) on delete cascade,
  external_game_id text unique,          -- Odds API game id (optional)
  commence_time timestamptz not null,
  home_team_id integer not null references public.teams(id),
  away_team_id integer not null references public.teams(id),
  status text not null default 'scheduled', -- scheduled | in_progress | final | postponed
  final_scores jsonb                      -- {home:int, away:int}
);

-- file: schemas/0200_05_game_lines.sql
-- LINES (one active line per game)
create table if not exists public.game_lines (
  id integer generated by default as identity primary key,
  game_id uuid not null references public.games(id) on delete cascade,
  source text not null default 'fanduel',
  spread_team_id integer not null references public.teams(id), -- team giving/taking points
  spread_value numeric not null,                               -- negative = favorite
  fetched_at timestamptz not null default now(),
  is_active_line boolean not null default false
);

-- At most one active line per game
create unique index if not exists ux_game_lines_active
on public.game_lines (game_id)
where is_active_line = true;

-- file: schemas/0200_06_picks.sql
create table if not exists public.picks (
  user_id uuid not null references public.users(id) on delete cascade,
  game_id uuid not null references public.games(id) on delete cascade,
  picked_team_id integer not null references public.teams(id),
  weight public.weight_enum not null,
  -- final frozen snapshot at the moment of the last pre-kickoff change
  locked_at timestamptz,
  locked_line_id integer,
  locked_spread_team_id integer,
  locked_spread_value numeric,
  locked_by uuid not null default auth.uid(),
  primary key (user_id, game_id)
);

-- file: schemas/0200_07_results.sql
-- RESULTS
create table if not exists public.results (
  game_id uuid primary key references public.games(id) on delete cascade,
  winning_team_id integer,
  cover_result text, -- 'home' | 'away' | 'push'
  graded_at timestamptz not null default now()
);

-- file: schemas/0200_08_totals.sql
-- TOTALS
create table if not exists public.totals (
  user_id uuid not null references public.users(id) on delete cascade,
  week_id integer not null references public.weeks(id) on delete cascade,
  points_delta int not null default 0,
  season_total_cached int not null default 0,
  primary key (user_id, week_id)
);

-- file: schemas/0200_09_settings.sql
-- SETTINGS
create table if not exists public.settings (
  id boolean primary key default true, -- single row table
  odds_api_monthly_cap int not null default 500,
  odds_api_calls_used_current_month int not null default 0,
  reset_on date
);

-- file: schemas/0200_10_audit_log.sql
-- AUDIT
create table if not exists public.audit_log (
  id integer generated by default as identity primary key,
  actor uuid references public.users(id),
  action text not null,
  details jsonb,
  created_at timestamptz not null default now()
);

-- file: schemas/0200_11_cron_run_log.sql
-- ---------------------------------------------------------------------------
-- cron_run_log
-- ---------------------------------------------------------------------------
create table if not exists public.cron_run_log (
  id          bigint generated always as identity primary key,
  job         text not null,
  started_at  timestamptz not null default now(),
  finished_at timestamptz,
  ok          boolean,
  summary     jsonb,
  error       text
);
alter table public.cron_run_log enable row level security;

-- file: schemas/0201_picks.sql
-- file: schemas/0201_picks.sql

-- Ensure UUID generator is available
create extension if not exists pgcrypto;

-- 1) Add the surrogate id column used by server code and settlement FKs.
do $$
begin
  if not exists (
    select 1 from information_schema.columns
    where table_schema = 'public'
      and table_name = 'picks'
      and column_name = 'id'
  ) then
    alter table public.picks add column id uuid;
  end if;
end$$;

-- 2) Backfill existing ids.
update public.picks
set id = gen_random_uuid()
where id is null;

-- 3) Enforce NOT NULL + default for future inserts.
alter table public.picks
  alter column id set not null;

alter table public.picks
  alter column id set default gen_random_uuid();

-- 4) Add the group tenancy column.
alter table public.picks
  add column if not exists group_id uuid;

-- 5) Keep the surrogate id usable as an FK target after the PK moves.
do $$
begin
  if not exists (
    select 1 from pg_constraint
    where conrelid = 'public.picks'::regclass
      and conname = 'picks_id_key'
  ) then
    alter table public.picks
      add constraint picks_id_key unique (id);
  end if;
end$$;

-- file: schemas/0202_pick_settlement.sql
alter table public.settings add column if not exists missed_pick_penalty int default -1;

create table if not exists public.pick_settlement (
  group_id     uuid not null,
  user_id      uuid not null,
  game_id      uuid not null references public.games(id) on delete cascade,
  pick_id      uuid references public.picks(id) on delete cascade,
  points_delta int,
  outcome      public.pick_outcome,
  graded_at    timestamptz not null default now(),
  constraint pick_settlement_pkey primary key (group_id, user_id, game_id)
);

alter table public.pick_settlement
  add column if not exists group_id uuid;

-- keep unique link when a real pick exists
create unique index if not exists uq_pick_settlement_pick_id
  on public.pick_settlement(pick_id)
  where pick_id is not null;

-- more flexible constraint to allow configurable penalties (e.g., -2)
alter table public.pick_settlement
  drop constraint if exists pick_settlement_points_range;

alter table public.pick_settlement
  add constraint pick_settlement_points_range
  check (points_delta between -20 and 10);

-- helpful index for joins by game
create index if not exists idx_pick_settlement_game on public.pick_settlement(game_id);
create index if not exists idx_pick_settlement_group_game_user
  on public.pick_settlement(group_id, game_id, user_id);

-- RLS: readable, but no client writes
alter table public.pick_settlement enable row level security;

-- (A) Let authenticated users read settlements for their groups.
do $$
begin
  drop policy if exists "read settlements" on public.pick_settlement;
exception when undefined_object then null; end$$;

create policy "read settlements"
  on public.pick_settlement
  for select
  to authenticated
  using (public.is_member(group_id));

-- (B) Block all client writes; grading functions (SECURITY DEFINER) or service role will write
do $$
begin
  drop policy if exists "no client writes (insert)" on public.pick_settlement;
  drop policy if exists "no client writes (update)" on public.pick_settlement;
  drop policy if exists "no client writes (delete)" on public.pick_settlement;
exception when undefined_object then null; end$$;

create policy "no client writes (insert)"
  on public.pick_settlement
  for insert
  to authenticated
  with check (public.is_member(group_id) and false);

create policy "no client writes (update)"
  on public.pick_settlement
  for update
  to authenticated
  using (public.is_member(group_id) and false)
  with check (public.is_member(group_id) and false);

create policy "no client writes (delete)"
  on public.pick_settlement
  for delete
  to authenticated
  using (public.is_member(group_id) and false);

-- file: schemas/0204_require_locks.sql
-- Unstarted: use current active
update public.picks p
set locked_at = coalesce(p.locked_at, now()),
    locked_line_id = gl.id,
    locked_spread_team_id = gl.spread_team_id,
    locked_spread_value = gl.spread_value
from public.game_lines gl
join public.games g
  on g.id = gl.game_id
where p.game_id = gl.game_id
  and gl.is_active_line = true
  and now() < g.commence_time
  and (
    p.locked_line_id is null
    or p.locked_spread_team_id is null
    or p.locked_spread_value is null
  );

-- Started: use last line at/before kickoff (one per game via LATERAL)
update public.picks p
set locked_at = coalesce(p.locked_at, g.commence_time),
    locked_line_id = c.id,
    locked_spread_team_id = c.spread_team_id,
    locked_spread_value = c.spread_value
from public.games g
join lateral (
  select gl.*
  from public.game_lines gl
  where gl.game_id = g.id
    and gl.fetched_at <= g.commence_time
  order by gl.fetched_at desc, gl.id desc
  limit 1
) c on true
where p.game_id = g.id
  and now() >= g.commence_time
  and (
    p.locked_line_id is null
    or p.locked_spread_team_id is null
    or p.locked_spread_value is null
  );

-- Only make these NOT NULL after the backfill above succeeds
alter table public.picks
  alter column locked_at             set not null,
  alter column locked_spread_team_id set not null,
  alter column locked_spread_value   set not null;

-- file: schemas/0205_push_subscriptions.sql
-- ---------------------------------------------------------------------------
-- push_subscriptions
-- One row per browser/device push endpoint. RLS: owners manage their own rows;
-- the service role (push sender) bypasses RLS to read every subscription.
-- ---------------------------------------------------------------------------
create table if not exists public.push_subscriptions (
  id           uuid primary key default gen_random_uuid(),
  user_id      uuid not null references public.users(id) on delete cascade,
  endpoint     text not null unique,
  p256dh       text not null,
  auth_key     text not null,
  user_agent   text,
  created_at   timestamptz not null default now(),
  last_seen_at timestamptz not null default now()
);

create index if not exists idx_push_subscriptions_user
  on public.push_subscriptions (user_id);

alter table public.push_subscriptions enable row level security;

-- file: schemas/0206_notification_log.sql
-- ---------------------------------------------------------------------------
-- notification_log
-- Audit trail + dedupe ledger for sent push notifications. Written by the
-- service role only; users may read their own rows via RLS.
--   kind:   'pick_reminder' | 'line_shift' | 'test'
--   detail: e.g. { "from": -3, "to": -5.5, "threshold": 2 }
-- ---------------------------------------------------------------------------
create table if not exists public.notification_log (
  id         uuid primary key default gen_random_uuid(),
  user_id    uuid not null references public.users(id) on delete cascade,
  kind       text not null,
  game_id    uuid references public.games(id) on delete cascade,
  week_id    integer references public.weeks(id) on delete cascade,
  detail     jsonb,
  created_at timestamptz not null default now()
);

create index if not exists idx_notification_log_user_kind_game
  on public.notification_log (user_id, kind, game_id);

alter table public.notification_log enable row level security;

-- file: schemas/0207_notification_prefs.sql
-- ---------------------------------------------------------------------------
-- users.notification_prefs
-- Per-user notification settings: a master switch plus per-trigger config.
-- Added as a separate ALTER so the legacy users table source stays untouched.
--   { "enabled": bool,
