  foreign key (group_id)
  references public.groups(id)
  on delete cascade;

-- file: schemas/0211_group_config.sql
-- GROUP_CONFIG: one row per group, holds group-owned gameplay settings.
-- Operational settings (odds-quota caps, penalties) remain on the global settings table.
create table if not exists public.group_config (
  group_id    uuid primary key references public.groups(id) on delete cascade,
  -- Which odds source this group uses for its active line
  line_source text not null default 'fanduel',
  -- Flexible JSONB bag for gameplay rule knobs (drop-worst-week, multipliers, etc.)
  -- Future rule features (issue #107) write their settings here.
  scoring_rules jsonb not null default '{}',
  created_at  timestamptz not null default now(),
  updated_at  timestamptz not null default now()
);

-- file: schemas/0212_group_week_overrides.sql
-- GROUP_WEEK_OVERRIDES: per-week rule overrides for a group, keyed (group_id, week_id).
-- Never added as columns on the global weeks table (ADR-0002).
create table if not exists public.group_week_overrides (
  group_id   uuid    not null references public.groups(id) on delete cascade,
  week_id    integer not null references public.weeks(id) on delete cascade,
  -- Special-week rule overrides (e.g. double-points week, locked weights)
  overrides  jsonb   not null default '{}',
  created_at timestamptz not null default now(),
  primary key (group_id, week_id)
);

-- file: schemas/0213_seed_original_group_config.sql
-- Seed group_config for the original "Sunday Bets" group.
-- Copies gameplay-relevant settings from the global settings table into the
-- group-owned config row. Operational settings (quota caps, reset dates) stay global.
-- Safe to re-run: ON CONFLICT updates scoring_rules from current global settings.
insert into public.group_config (group_id, line_source, scoring_rules)
select
  '00000000-0000-4000-8000-000000000017'::uuid,
  'fanduel',
  jsonb_build_object(
    'missed_pick_penalty',
    coalesce(
      (select missed_pick_penalty from public.settings where id = true limit 1),
      -1
    )
  )
on conflict (group_id) do update set
  scoring_rules = excluded.scoring_rules,
  updated_at    = now();

-- file: schemas/0214_avatar_key.sql
alter table public.users add column if not exists avatar_key text;

-- file: schemas/0215_comments.sql
create table if not exists public.comments (
  id uuid primary key default gen_random_uuid(),
  group_id uuid not null references public.groups(id) on delete cascade,
  user_id uuid not null references public.users(id) on delete cascade,
  game_id uuid not null references public.games(id) on delete cascade,
  body text not null,
  created_at timestamptz not null default now(),
  constraint comments_body_not_blank check (length(btrim(body)) > 0)
);

create index if not exists idx_comments_group_game
  on public.comments (group_id, game_id, created_at);

-- file: schemas/0215_schedule_game_id.sql
-- Add ESPN event id as an observability/re-sync attribute (not an identity key).
alter table public.games
  add column if not exists schedule_game_id text;

-- Defensively remove any duplicate matchups before adding the constraint.
-- Partition on the normalized (unordered) team pair so reversed home/away rows
-- from different providers are treated as the same matchup.
with ranked as (
  select id,
         row_number() over (
           partition by week_id, least(home_team_id, away_team_id), greatest(home_team_id, away_team_id)
           order by
             (external_game_id is null)::int, -- keep rows that already have an Odds id
             id asc
         ) as rn
  from public.games
)
delete from public.games g
using ranked r
where g.id = r.id
  and r.rn > 1;

-- The durable identity of a game is its matchup within a week.
-- Use an expression index on the normalized (unordered) team pair so that a
-- home/away disagreement between providers cannot create a duplicate row.
-- Provider ids (external_game_id, schedule_game_id) are attributes, not the key.
create unique index uq_games_matchup
  on public.games (week_id, least(home_team_id, away_team_id), greatest(home_team_id, away_team_id));

-- file: schemas/0216_reactions.sql
create table if not exists public.reactions (
  id uuid primary key default gen_random_uuid(),
  group_id uuid not null references public.groups(id) on delete cascade,
  user_id uuid not null references public.users(id) on delete cascade,
  game_id uuid not null references public.games(id) on delete cascade,
  emoji text not null,
  created_at timestamptz not null default now(),
  constraint reactions_emoji_not_blank check (length(btrim(emoji)) > 0),
  -- one reaction per emoji per user per game per group
  constraint reactions_unique_user_game_emoji unique (group_id, user_id, game_id, emoji)
);

create index if not exists idx_reactions_group_game
  on public.reactions (group_id, game_id);

