-- file: views/leaderboard_season_totals.sql
-- One row per user per (group, season) with totals + ranks.
-- Drop-worst-week (ADR-0005): when a group enables
-- group_config.scoring_rules.drop_worst_week, a player's single lowest-scoring
-- week is omitted from total_points once they have 2+ settled weeks. The drop
-- forgives points only -- the W/L/push record and tie-breakers still count the
-- dropped week.
create or replace view public.leaderboard_season_totals as
with season_rows as (
select
ps.user_id,
u.display_name,
u.avatar_key,
s.year as season_year,
w.id as week_id,
ps.points_delta,
ps.outcome,
ps.group_id
from public.pick_settlement ps
join public.games g on g.id = ps.game_id
join public.weeks w on w.id = g.week_id
join public.seasons s on s.id = w.season_id
join public.users u on u.id = ps.user_id
)
-- Decision-level season aggregates: raw points and the W/L/push record.
-- Record counts intentionally include every week, even one later dropped
-- (ADR-0005: drop-worst-week forgives points, not record).
, totals as (
select
user_id,
display_name,
avatar_key,
season_year,
group_id,
sum(points_delta)::int as raw_total,
count(*)::int as decisions,
count(*) filter (where outcome = 'win')::int as wins,
count(*) filter (where outcome = 'loss')::int as losses,
count(*) filter (where outcome = 'push')::int as pushes,
count(*) filter (where outcome = 'missed')::int as missed
from season_rows
group by user_id, display_name, avatar_key, season_year, group_id
)
-- Week-level points per player, used to find the single lowest week.
, week_points as (
select
user_id,
season_year,
group_id,
week_id,
sum(points_delta)::int as wk_points
from season_rows
group by user_id, season_year, group_id, week_id
)
-- Per player: count of settled weeks and the lowest week's points.
, week_summary as (
select
user_id,
season_year,
group_id,
count(*)::int as weeks_played,
min(wk_points)::int as lowest_week_points
from week_points
group by user_id, season_year, group_id
)
-- Resolved drop-worst-week flag per group (default false when no config row).
, group_drop as (
select
g.id as group_id,
coalesce((gc.scoring_rules ->> 'drop_worst_week')::boolean, false) as drop_worst_week
from public.groups g
left join public.group_config gc on gc.group_id = g.id
)
, adjusted as (
select
t.user_id,
t.display_name,
t.avatar_key,
t.season_year,
t.group_id,
t.decisions,
t.wins,
t.losses,
t.pushes,
t.missed,
-- Drop the single lowest week's points only when the group enables it AND the
-- player has 2+ settled weeks (ADR-0005). Otherwise the raw total stands.
case
when gd.drop_worst_week and ws.weeks_played >= 2
then t.raw_total - ws.lowest_week_points
else t.raw_total
end::int as total_points
from totals t
join week_summary ws
on ws.user_id = t.user_id
and ws.season_year = t.season_year
and ws.group_id = t.group_id
join group_drop gd on gd.group_id = t.group_id
)
select
a.user_id,
a.display_name,
a.season_year,
a.total_points,
a.decisions,
a.wins,
a.losses,
a.pushes,
a.missed,
dense_rank() over (
partition by a.group_id, a.season_year
order by a.total_points desc, a.wins desc, a.pushes desc
) as rank,
a.group_id,
a.avatar_key
from adjusted a;

-- file: views/leaderboard_weekly_cumulative.sql
-- One row per user per (group, season, week) with week points and running total
create or replace view public.leaderboard_weekly_cumulative as
with week_rows as (
  select
    ps.user_id,
    u.display_name,
    s.year as season_year,
    w.week_number,
    sum(ps.points_delta)::int as week_points,
    count(*) filter (where ps.outcome = 'win')::int   as week_wins,
    count(*) filter (where ps.outcome = 'loss')::int  as week_losses,
    count(*) filter (where ps.outcome = 'push')::int  as week_pushes,
    count(*) filter (where ps.outcome = 'missed')::int as week_missed,
    ps.group_id
  from public.pick_settlement ps
  join public.games   g on g.id = ps.game_id
  join public.weeks   w on w.id = g.week_id
  join public.seasons s on s.id = w.season_id
  join public.users   u on u.id = ps.user_id
  group by ps.user_id, u.display_name, s.year, w.week_number, ps.group_id
),
cum as (
  select
    user_id,
    display_name,
    season_year,
    week_number,
    week_points,
    week_wins,
    week_losses,
    week_pushes,
    week_missed,
    -- running total per (group, user, season) ordered by week
    sum(week_points) over (
      partition by group_id, user_id, season_year
      order by week_number
      rows between unbounded preceding and current row
    )::int as cumulative_points,
    group_id
  from week_rows
)
select
  cum.user_id,
  cum.display_name,
  cum.season_year,
  cum.week_number,
  cum.week_points,
  cum.week_wins,
  cum.week_losses,
  cum.week_pushes,
  cum.week_missed,
  cum.cumulative_points,
  -- season total per (group, user, season)
  sum(cum.week_points) over (
    partition by cum.group_id, cum.user_id, cum.season_year
  )::int as season_total,
  dense_rank() over (
    partition by cum.group_id, cum.season_year, cum.week_number
    order by cum.cumulative_points desc
  ) as cumulative_rank_this_week,
  cum.group_id
from cum;

-- file: views/picks_group_view.sql
-- Group-scoped view of picks for started games.
-- security_invoker means the caller's RLS on public.picks is applied:
--   - members see their own picks always
--   - members see others' picks only after game_has_started (the sel_picks_owner_or_started policy)
-- The WHERE clause mirrors that restriction for performance and clarity.
create or replace view public.picks_group_view
with (security_invoker = on) as
select
  p.group_id,
  p.user_id,
  u.display_name,
  p.game_id,
  g.week_id,
  p.weight,
  (case
     when p.picked_team_id = g.home_team_id then 'home'
     when p.picked_team_id = g.away_team_id then 'away'
   end)::public.side_enum as picked_side,
  p.picked_team_id,
  t.short_name as picked_team_short,
  p.locked_spread_value,
  p.locked_spread_team_id,
  p.locked_at,
  g.commence_time,
  u.avatar_key
from public.picks p
join public.users u on u.id = p.user_id
join public.games g on g.id = p.game_id
join public.teams t on t.id = p.picked_team_id
where g.commence_time <= now();

revoke all on public.picks_group_view from public, anon;
grant select on public.picks_group_view to authenticated;

-- file: views/picks_status_view_admin.sql
create or replace view public.picks_status_view_admin
with (security_invoker = on) as
select
  p.game_id,
  g.week_id,
  p.user_id,
  u.display_name as user_display_name,
  p.weight,
  (case
     when p.picked_team_id = g.home_team_id then 'home'
     when p.picked_team_id = g.away_team_id then 'away'
   end)::public.side_enum as picked_side,
  p.picked_team_id,
  t.short_name as picked_team_short,
  p.locked_spread_value as locked_spread_value,
  p.locked_spread_team_id as locked_spread_team_id,
  p.locked_at,
  g.commence_time,
  (g.commence_time <= now()) as game_started,
  p.group_id
from public.picks p
join public.users u  on u.id = p.user_id
join public.games g  on g.id = p.game_id
join public.teams t  on t.id = p.picked_team_id;

revoke all on public.picks_status_view_admin from public;
grant select on public.picks_status_view_admin to service_role;

-- file: views/picks_status_view_user.sql
create or replace view public.picks_status_view_user
with (security_invoker = on) as
select
  p.game_id,
  g.week_id,
  p.user_id,
  p.weight,
  (case
     when p.picked_team_id = g.home_team_id then 'home'
     when p.picked_team_id = g.away_team_id then 'away'
   end)::public.side_enum as picked_side,
  p.picked_team_id,
  t.short_name as picked_team_short,
  p.locked_spread_value as locked_spread_value,
  p.locked_spread_team_id,
  p.locked_at,
  g.commence_time,
  (g.commence_time <= now()) as game_started,
  p.group_id
from public.picks p
join public.games g on g.id = p.game_id
join public.teams t on t.id = p.picked_team_id
where p.user_id = auth.uid();

revoke all on public.picks_status_view_user from public, anon;
grant select on public.picks_status_view_user to authenticated;

-- file: views/stats_accuracy_by_team_alltime.sql
create or replace view public.stats_accuracy_by_team_alltime
with (security_invoker = on) as
select
  ps.user_id,
  u.display_name,
  p.picked_team_id as team_id,
  t.name as team_name,
  t.short_name as team_short_name,
  count(*)::int as decisions,
  count(*) filter (where ps.outcome = 'win')::int as wins,
  count(*) filter (where ps.outcome = 'loss')::int as losses,
  count(*) filter (where ps.outcome = 'push')::int as pushes,
  sum(ps.points_delta)::int as points,
  round(
    count(*) filter (where ps.outcome = 'win')::numeric
      / nullif(count(*) filter (where ps.outcome in ('win', 'loss')), 0),
    4
  ) as accuracy,
  ps.group_id
from public.pick_settlement ps
join public.picks p on p.id = ps.pick_id
join public.users u on u.id = ps.user_id
join public.teams t on t.id = p.picked_team_id
group by ps.user_id, u.display_name, p.picked_team_id, t.name, t.short_name, ps.group_id;

revoke all on public.stats_accuracy_by_team_alltime from public, anon, authenticated;
grant select on public.stats_accuracy_by_team_alltime to service_role;

