-- file: functions/_private/get_final_week_unlimited_allin.sql
-- Returns the final_week_unlimited_allin gameplay flag.
-- SECURITY DEFINER so lock_pick (SECURITY INVOKER) can read settings
-- without granting authenticated users broad access to the settings table.
create or replace function public._get_final_week_unlimited_allin()
returns boolean
language sql
security definer
stable
set search_path = public
as $$
  select coalesce(
    (select s.final_week_unlimited_allin from public.settings s where s.id = true),
    true
  );
$$;

-- Reachable by `authenticated` through lock_pick / lock_pick_all_groups (SECURITY
-- INVOKER), so the caller needs EXECUTE even though this is SECURITY DEFINER. The
-- closed-by-default baseline (ADR-0011) revokes PUBLIC, so this grant is the sole path.
grant execute on function public._get_final_week_unlimited_allin()
  to authenticated, service_role;

-- file: functions/_private/grade_games_by_ids.sql
-- This is a new internal helper function. Note the leading underscore.
create or replace function public._grade_games_by_ids(p_game_ids uuid[])
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  -- (1) Upsert settlements for users who DID make a pick on the given games
  insert into public.pick_settlement (group_id, user_id, game_id, pick_id, points_delta, outcome, graded_at)
  select
    p.group_id,
    p.user_id,
    g.id,
    p.id,
    gp.points_delta,
    gp.outcome,
    now()
  from public.games g
  join public.picks p on p.game_id = g.id
  cross join lateral public.grade_pick(
    (g.final_scores->>'home')::int,
    (g.final_scores->>'away')::int,
    g.home_team_id,
    g.away_team_id,
    p.picked_team_id,
    p.locked_spread_team_id,
    p.locked_spread_value,
    p.weight::text
  ) as gp
  where g.id = any(p_game_ids)
  on conflict (group_id, user_id, game_id)
  do update set
    pick_id      = excluded.pick_id,
    points_delta = excluded.points_delta,
    outcome      = excluded.outcome,
    graded_at    = excluded.graded_at;

  -- (2) Upsert "missed" penalties for users who did NOT make a pick
  insert into public.pick_settlement (group_id, user_id, game_id, pick_id, points_delta, outcome, graded_at)
  select
    gm.group_id,
    u.id,
    g.id,
    null,
    public.resolve_missed_penalty_for_game(g.id),
    'missed'::public.pick_outcome,
    now()
  from public.games g
  cross join public.group_memberships gm
  join public.users u on u.id = gm.user_id and u.role = 'player'
  where g.id = any(p_game_ids)
    and not exists (
      select 1
      from public.picks p
      where p.group_id = gm.group_id
        and p.game_id = g.id
        and p.user_id = u.id
    )
  on conflict (group_id, user_id, game_id)
  do update set
    -- Only update if the existing settlement is also for a missed pick.
    -- This prevents overwriting a real pick that was graded out of order.
    pick_id      = excluded.pick_id,
    points_delta = excluded.points_delta,
    outcome      = excluded.outcome,
    graded_at    = excluded.graded_at
  where pick_settlement.pick_id is null;
end;
$$;

-- file: functions/_private/resolve_missed_penalty.sql
create or replace function public.resolve_missed_penalty_for_game(p_game_id uuid)
returns int
language sql
stable
set search_path = public
as $$
  -- Return a negative penalty based solely on settings.
  -- If the settings row is missing or the value is null, default to 1.
  select -abs(
    coalesce(
      (select missed_pick_penalty from public.settings where id = true),
      1
    )
  )
$$;

-- file: functions/_private/weight_points.sql
create or replace function public.weight_points(p_weight text)
returns int
language sql
immutable
as $$
  select case upper(p_weight)
    when 'L' then 1 when 'M' then 3 when 'H' then 5 when 'A' then 10 else 0 end
$$;

-- file: functions/auth/handle_new_auth_user.sql
-- Function: insert a row into public.users when a new auth.users row is created
create or replace function public.handle_new_auth_user()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_display_name text;
begin
  -- Choose a safe, non-null display_name:
  --   1) raw_user_meta_data.display_name
  --   2) raw_user_meta_data.full_name
  --   3) email local-part
  --   4) fallback based on uuid
  v_display_name := coalesce(
    (new.raw_user_meta_data ->> 'display_name'),
    (new.raw_user_meta_data ->> 'full_name'),
    split_part(new.email, '@', 1),
    'user-' || left(new.id::text, 8)
  );

  insert into public.users (id, display_name, role)
  values (new.id, v_display_name, 'player')
  on conflict (id) do nothing;

  return new;
end;
$$;

-- Fire AFTER INSERT on auth.users to mirror into public.users
drop trigger if exists on_auth_user_created on auth.users;
create trigger on_auth_user_created
after insert on auth.users
for each row execute function public.handle_new_auth_user();

-- file: functions/auth/handle_updated_auth_user.sql
-- Function: keep public.users.display_name in sync if auth metadata later changes
create or replace function public.handle_updated_auth_user()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_display_name text;
begin
  -- Only bother if display_name/full_name changed or was added
  if (coalesce(new.raw_user_meta_data ->> 'display_name','') is distinct from coalesce(old.raw_user_meta_data ->> 'display_name',''))
     or (coalesce(new.raw_user_meta_data ->> 'full_name','')   is distinct from coalesce(old.raw_user_meta_data ->> 'full_name',''))
  then
    v_display_name := coalesce(
      (new.raw_user_meta_data ->> 'display_name'),
      (new.raw_user_meta_data ->> 'full_name'),
      split_part(new.email, '@', 1),
      'user-' || left(new.id::text, 8)
    );

    update public.users
       set display_name = v_display_name
     where id = new.id;
  end if;

  return new;
end;
$$;

-- Keep display_name synced on later auth-metadata changes
drop trigger if exists on_auth_user_updated on auth.users;
create trigger on_auth_user_updated
after update on auth.users
for each row execute function public.handle_updated_auth_user();

-- file: functions/auth/is_commissioner.sql
create or replace function public.is_commissioner(target_group_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public, pg_temp
as $$
  select coalesce(
    (select auth.uid()) is not null
    and exists (
      select 1
      from public.group_memberships gm
      where gm.group_id = target_group_id
        and gm.user_id = (select auth.uid())
        and gm.role = 'commissioner'
    ),
    false
  );
$$;

revoke execute on function public.is_commissioner(uuid) from public, anon;

-- file: functions/games/attach_line_to_matchup.sql
-- Odds sync helper: finds a game by the unordered team pair within a week,
-- attaches external_game_id if currently NULL, and returns the game's uuid.
-- Returns NULL when no matching matchup exists — caller should skip and report.
-- Never flips home/away; the schedule source is canonical for home/away.
create or replace function public.attach_line_to_matchup(
  p_week_id          int,
  p_home_team_id     int,
  p_away_team_id     int,
  p_external_game_id text
) returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_id uuid;
begin
  -- Match on the unordered team pair so a home/away disagreement between
  -- providers does not create a duplicate or silently miss the game.
  select id into v_id
  from public.games
  where week_id = p_week_id
    and (
      (home_team_id = p_home_team_id and away_team_id = p_away_team_id)
      or
      (home_team_id = p_away_team_id and away_team_id = p_home_team_id)
    )
  limit 1;

  if v_id is null then
    return null;
  end if;

  -- Set external_game_id only when not yet claimed; never overwrite.
  update public.games
  set external_game_id = p_external_game_id
  where id = v_id
    and external_game_id is null;

  return v_id;
end
$$;

grant execute on function public.attach_line_to_matchup(int,int,int,text)
  to service_role;

-- file: functions/games/upsert_game_by_external_id.sql
create or replace function public.upsert_game_by_external_id(
  p_external_game_id text,
  p_week_id          int,
  p_commence         timestamptz,
  p_home_team_id     int,
  p_away_team_id     int
) returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_id uuid;
begin
  insert into public.games (
    week_id, external_game_id, commence_time, home_team_id, away_team_id, status
  )
  values (
    p_week_id, p_external_game_id, p_commence, p_home_team_id, p_away_team_id, 'scheduled'
  )
  on conflict on constraint uq_games_external
  do update set
    week_id       = excluded.week_id,
    commence_time = excluded.commence_time,
    home_team_id  = excluded.home_team_id,
    away_team_id  = excluded.away_team_id
  returning id into v_id;

  return v_id;
end
$$;

grant execute on function public.upsert_game_by_external_id(text,int,timestamptz,int,int)
  to service_role;

-- file: functions/games/upsert_game_by_matchup.sql
-- Schedule sync writer: creates or updates a game row by the matchup key
-- (week_id, home_team_id, away_team_id).  Provider ids are attributes.
-- Returns the game's uuid — same id for the life of the matchup.
create or replace function public.upsert_game_by_matchup(
  p_week_id          int,
  p_home_team_id     int,
  p_away_team_id     int,
  p_commence         timestamptz,
  p_schedule_game_id text,
  p_status           text default 'scheduled'
) returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_id uuid;
begin
  insert into public.games (
    week_id, home_team_id, away_team_id, commence_time, schedule_game_id, status
  )
  values (
    p_week_id, p_home_team_id, p_away_team_id,
    p_commence, p_schedule_game_id,
    coalesce(p_status, 'scheduled')
  )
  on conflict (week_id, least(home_team_id, away_team_id), greatest(home_team_id, away_team_id))
  do update set
    commence_time    = excluded.commence_time,
    schedule_game_id = excluded.schedule_game_id,
    -- Only advance status; never overwrite a terminal state from schedule sync.
    status           = case
                         when public.games.status in ('final', 'cancelled') then public.games.status
                         else excluded.status
                       end
  returning id into v_id;

  return v_id;
end
$$;

grant execute on function public.upsert_game_by_matchup(int,int,int,timestamptz,text,text)
  to service_role;

-- file: functions/grade/advance_week_if_complete.sql
create or replace function public.advance_week_if_complete()
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_week       record;
  v_total_games  int;
  v_final_games  int;
  v_total_picks  int;
  v_settled_picks int;
begin
  select id, week_number into v_week
  from public.weeks
  where end_ts < now()
  order by end_ts desc
  limit 1;

  if v_week is null then
    return jsonb_build_object('ok', true, 'reason', 'no_concluded_week');
  end if;

  select
    count(*) filter (where status != 'postponed'),
    count(*) filter (where status != 'postponed' and (final_scores->>'home') is not null)
  into v_total_games, v_final_games
  from public.games
  where week_id = v_week.id;

  select count(*) into v_total_picks
  from public.picks p
  join public.games g on g.id = p.game_id
  where g.week_id = v_week.id
    and g.status != 'postponed';

  select count(*) into v_settled_picks
  from public.pick_settlement ps
  join public.games g on g.id = ps.game_id
  where g.week_id = v_week.id
    and g.status != 'postponed';

  return jsonb_build_object(
    'ok',             v_final_games = v_total_games and v_settled_picks = v_total_picks,
    'week_id',        v_week.id,
    'week_number',    v_week.week_number,
    'total_games',    v_total_games,
    'final_games',    v_final_games,
    'total_picks',    v_total_picks,
    'settled_picks',  v_settled_picks
  );
end;
$$;

-- file: functions/grade/grade_game.sql
create or replace function public.grade_game(p_game_id uuid)
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  -- Ensure the game has scores before proceeding
  if not exists (
    select 1 from public.games
    where id = p_game_id and (final_scores->>'home') is not null
  ) then
    raise exception 'grade_game: game % has no final scores', p_game_id;
  end if;

  -- Call the core grading function with a single game ID
  perform public._grade_games_by_ids(array[p_game_id]);
end;
$$;

-- file: functions/grade/grade_pick.sql
create or replace function public.grade_pick(
  home_pts int,
  away_pts int,
  home_id int,
  away_id int,
  picked_team_id int,
  spread_team_id int,
  spread_value numeric,
  weight text
) returns table(points_delta int, outcome public.pick_outcome)
language sql immutable
as $$
  with m as (
    select public.ats_margin_at_lock(home_pts, away_pts, home_id, away_id, spread_team_id, spread_value) as margin,
           public.weight_points(weight) as points_value
  )
  select
    case
      when margin = 0 then 0
      when (margin > 0 and picked_team_id = home_id)
        or (margin < 0 and picked_team_id = away_id)
        then points_value
      else -points_value
    end as points_delta,
    case
      when margin = 0 then 'push'::public.pick_outcome
      when (margin > 0 and picked_team_id = home_id)
        or (margin < 0 and picked_team_id = away_id)
        then 'win'::public.pick_outcome
      else 'loss'::public.pick_outcome
    end as outcome
  from m;
$$;

-- file: functions/grade/grade_season.sql
create or replace function public.grade_season(p_season_id int)
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  v_game_ids uuid[];
begin
  -- Collect all final games for the season
  select array_agg(g.id)
  into v_game_ids
  from public.weeks w
  join public.games g on g.week_id = w.id
  where w.season_id = p_season_id
    and (g.final_scores->>'home') is not null;

  -- Call the core grading function with the collected game IDs
  if array_length(v_game_ids, 1) > 0 then
    perform public._grade_games_by_ids(v_game_ids);
  end if;
end;
$$;

-- file: functions/grade/grade_week.sql
create or replace function public.grade_week(p_week_id int)
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  v_game_ids uuid[];
begin
  -- Collect all final games for the week
  select array_agg(id)
  into v_game_ids
  from public.games
  where week_id = p_week_id
    and (final_scores->>'home') is not null;

  -- Call the core grading function with the collected game IDs
  if array_length(v_game_ids, 1) > 0 then
    perform public._grade_games_by_ids(v_game_ids);
  end if;
end;
$$;

-- file: functions/groups/create_group.sql
-- create_group: gated, atomic group creation (ADR-0006, decision 3).
--
-- The whole function runs in a single transaction, so a failure at any step
-- (gate rejection, constraint violation) leaves no orphan group, config, or
-- membership. SECURITY DEFINER lets it write groups / group_config /
-- group_memberships even though those tables block direct client writes; the
-- trust check is the gate below, keyed on the caller's auth.uid().
--
-- Error codes (surfaced to the caller as PostgrestError.code):
--   P0001  not authenticated
--   P0010  group name is required
--   P0011  group name too long
--   P0012  group creation not enabled for this account (gated mode)
create or replace function public.create_group(p_name text)
returns uuid
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_user_id  uuid;
  v_name     text;
  v_mode     text;
  v_capable  boolean;
  v_group_id uuid;
begin
  v_user_id := auth.uid();

  if v_user_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Validate name: non-empty, length-bounded (mirrors groups_name_max_len).
  v_name := btrim(coalesce(p_name, ''));
  if length(v_name) = 0 then
    raise exception 'group name is required' using errcode = 'P0010';
  end if;
  if length(v_name) > 60 then
    raise exception 'group name too long' using errcode = 'P0011';
  end if;

  -- Gate: global mode, then per-user capability when gated.
  select group_creation_mode into v_mode
  from public.settings
  where id = true
  limit 1;
  v_mode := coalesce(v_mode, 'gated');

  if v_mode <> 'open' then
    select can_create_group into v_capable
    from public.users
    where id = v_user_id;

    if not coalesce(v_capable, false) then
      raise exception 'group creation is not enabled for this account'
        using errcode = 'P0012';
    end if;
  end if;

  -- Atomic create: group, then its seeded config, then the creator as commissioner.
  insert into public.groups (name)
  values (v_name)
  returning id into v_group_id;

  -- Seed group_config from global settings, reusing the shape established by
  -- 0213_seed_original_group_config.sql so every group starts consistently.
  insert into public.group_config (group_id, line_source, scoring_rules)
  values (
    v_group_id,
    'fanduel',
    jsonb_build_object(
      'missed_pick_penalty',
      coalesce((select missed_pick_penalty from public.settings where id = true limit 1), -1)
    )
  );

  insert into public.group_memberships (group_id, user_id, role, status)
  values (v_group_id, v_user_id, 'commissioner', 'active');

  return v_group_id;
end;
$$;

revoke execute on function public.create_group(text) from public, anon;

-- file: functions/groups/leave_group.sql
-- leave_group: the calling user leaves the given group (ADR-0006, dec. 5).
--
-- Last-commissioner guard: if the caller is a commissioner and they are the
-- ONLY commissioner of the group, leaving is blocked. Another member must be
-- promoted to commissioner first (transfer-required, not block-only).
--
-- Error codes:
--   P0001  not authenticated
--   P0021  caller is not a member of this group
--   P0022  cannot leave as the last commissioner (promote another first)
create or replace function public.leave_group(p_group_id uuid)
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_caller_id          uuid;
  v_caller_role        public.group_membership_role;
  v_commissioner_count integer;
begin
  v_caller_id := auth.uid();

  if v_caller_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Caller must be a member.
  select role into v_caller_role
  from public.group_memberships
  where group_id = p_group_id and user_id = v_caller_id;

  if not found then
    raise exception 'caller is not a member of this group' using errcode = 'P0021';
  end if;

  -- Last-commissioner guard.
  if v_caller_role = 'commissioner' then
    select count(*) into v_commissioner_count
    from public.group_memberships
    where group_id = p_group_id and role = 'commissioner';

    if v_commissioner_count <= 1 then
      raise exception 'cannot leave as the last commissioner; promote another member first'
        using errcode = 'P0022';
    end if;
  end if;

  delete from public.group_memberships
  where group_id = p_group_id and user_id = v_caller_id;
end;
$$;

revoke execute on function public.leave_group(uuid) from public, anon;

-- file: functions/groups/mint_invite.sql
-- mint_invite: commissioner creates an invite for their group (ADR-0006, dec. 2 + 4).
--
-- Generates a random URL-safe code, inserts the invite row, and returns the code.
-- max_uses = NULL means unlimited uses; expires_at = NULL means no expiry.
--
-- Error codes:
--   P0001  not authenticated
--   P0020  caller is not a commissioner of the group
create or replace function public.mint_invite(
  p_group_id  uuid,
  p_max_uses  integer  default null,
  p_expires_at timestamptz default null
)
returns text
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_caller_id uuid;
  v_code      text;
begin
  v_caller_id := auth.uid();

  if v_caller_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  if not public.is_commissioner(p_group_id) then
    raise exception 'caller is not a commissioner of this group' using errcode = 'P0020';
  end if;

  -- Generate a compact URL-safe token using two UUID hex strings (no external deps).
  -- gen_random_uuid() is always available; we combine two and trim to 24 chars.
  v_code := replace(gen_random_uuid()::text, '-', '') || replace(gen_random_uuid()::text, '-', '');
  v_code := left(v_code, 24);

  insert into public.group_invites (group_id, created_by, code, max_uses, expires_at)
  values (p_group_id, v_caller_id, v_code, p_max_uses, p_expires_at);

  return v_code;
end;
$$;

revoke execute on function public.mint_invite(uuid, integer, timestamptz) from public, anon;

-- file: functions/groups/preview_invite.sql
create or replace function public.preview_invite(p_code text)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_user_id uuid;
  v_invite  public.group_invites%rowtype;
  v_group_name text;
begin
  v_user_id := auth.uid();

  if v_user_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Read-only preview for the /join/[code] page. Invite SELECT is
  -- commissioner-only under RLS (27_policies_group_invites.sql), so an invitee
  -- cannot see their own invite directly; this SECURITY DEFINER function exposes
  -- only the display state (never the raw row). redeem_invite re-validates
  -- atomically on submit, so this is advisory.
  select * into v_invite
  from public.group_invites
  where code = p_code;

  if not found then
    return jsonb_build_object('status', 'invalid', 'group_name', null);
  end if;

  if v_invite.revoked_at is not null then
    return jsonb_build_object('status', 'revoked', 'group_name', null);
  end if;

  if v_invite.expires_at is not null and v_invite.expires_at < now() then
    return jsonb_build_object('status', 'expired', 'group_name', null);
  end if;

  if v_invite.max_uses is not null and v_invite.used_count >= v_invite.max_uses then
    return jsonb_build_object('status', 'exhausted', 'group_name', null);
  end if;

  if exists (
    select 1 from public.group_memberships
    where group_id = v_invite.group_id and user_id = v_user_id
  ) then
    return jsonb_build_object('status', 'already_member', 'group_name', null);
  end if;

  select name into v_group_name from public.groups where id = v_invite.group_id;

  return jsonb_build_object('status', 'valid', 'group_name', v_group_name);
end;
$$;

revoke execute on function public.preview_invite(text) from public, anon;

-- file: functions/groups/promote_member.sql
-- promote_member: commissioner promotes a plain member to commissioner (ADR-0006, dec. 4 + 5).
--
-- A group may have multiple commissioners. Promoting a member is the only way
-- to satisfy the last-commissioner guard before a commissioner leaves or is removed.
--
-- Error codes:
--   P0001  not authenticated
--   P0020  caller is not a commissioner of the group
--   P0021  target user is not a member of this group
--   P0024  target user is already a commissioner
create or replace function public.promote_member(p_group_id uuid, p_user_id uuid)
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_caller_id   uuid;
  v_target_role public.group_membership_role;
begin
  v_caller_id := auth.uid();

  if v_caller_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Caller must be a commissioner of this group.
  if not public.is_commissioner(p_group_id) then
    raise exception 'caller is not a commissioner of this group' using errcode = 'P0020';
  end if;

  -- Target must be a member.
  select role into v_target_role
  from public.group_memberships
  where group_id = p_group_id and user_id = p_user_id;

  if not found then
    raise exception 'target user is not a member of this group' using errcode = 'P0021';
  end if;

  if v_target_role = 'commissioner' then
    raise exception 'target user is already a commissioner' using errcode = 'P0024';
  end if;

  update public.group_memberships
  set role = 'commissioner'
  where group_id = p_group_id and user_id = p_user_id;
end;
$$;

revoke execute on function public.promote_member(uuid, uuid) from public, anon;

-- file: functions/groups/redeem_invite.sql
create or replace function public.redeem_invite(p_code text)
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_user_id uuid;
  v_invite  public.group_invites%rowtype;
begin
  v_user_id := auth.uid();

  if v_user_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Lock the invite row to prevent concurrent over-limit redemption.
  select * into v_invite
  from public.group_invites
  where code = p_code
  for update;

  if not found then
    raise exception 'invite not found' using errcode = 'P0002';
  end if;

  if v_invite.revoked_at is not null then
    raise exception 'invite revoked' using errcode = 'P0003';
  end if;

  if v_invite.expires_at is not null and v_invite.expires_at < now() then
    raise exception 'invite expired' using errcode = 'P0004';
  end if;

  if v_invite.max_uses is not null and v_invite.used_count >= v_invite.max_uses then
    raise exception 'invite exhausted' using errcode = 'P0005';
  end if;

  -- No-op if the caller is already a member of this group.
  if exists (
    select 1 from public.group_memberships
    where group_id = v_invite.group_id and user_id = v_user_id
  ) then
    return;
  end if;

  -- Atomically add membership and increment usage counter.
  insert into public.group_memberships (group_id, user_id, role)
  values (v_invite.group_id, v_user_id, 'member');

  update public.group_invites
  set used_count = used_count + 1
  where id = v_invite.id;
end;
$$;

revoke execute on function public.redeem_invite(text) from public, anon;

-- file: functions/groups/remove_member.sql
-- remove_member: commissioner removes another member from their group (ADR-0006, dec. 4 + 5).
--
-- Last-commissioner guard: if the target member is a commissioner AND they are
-- the ONLY commissioner, the removal is blocked — another commissioner must be
-- promoted first.
--
-- Error codes:
--   P0001  not authenticated
--   P0020  caller is not a commissioner of the group
--   P0021  target user is not a member of this group
--   P0022  cannot remove the last commissioner (promote another first)
--   P0023  cannot remove yourself via this call (use leave_group)
create or replace function public.remove_member(p_group_id uuid, p_user_id uuid)
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_caller_id     uuid;
  v_target_role   public.group_membership_role;
  v_commissioner_count integer;
begin
  v_caller_id := auth.uid();

  if v_caller_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Caller must not be removing themselves via this call.
  if v_caller_id = p_user_id then
    raise exception 'cannot remove yourself; use leave_group instead' using errcode = 'P0023';
  end if;

  -- Caller must be a commissioner of this group.
  if not public.is_commissioner(p_group_id) then
    raise exception 'caller is not a commissioner of this group' using errcode = 'P0020';
  end if;

  -- Target must be a member.
  select role into v_target_role
  from public.group_memberships
  where group_id = p_group_id and user_id = p_user_id;

  if not found then
    raise exception 'target user is not a member of this group' using errcode = 'P0021';
  end if;

  -- Last-commissioner guard: if target is a commissioner, ensure another exists.
  if v_target_role = 'commissioner' then
    select count(*) into v_commissioner_count
    from public.group_memberships
    where group_id = p_group_id and role = 'commissioner';

    if v_commissioner_count <= 1 then
      raise exception 'cannot remove the last commissioner; promote another member first'
        using errcode = 'P0022';
    end if;
  end if;

  delete from public.group_memberships
  where group_id = p_group_id and user_id = p_user_id;
end;
$$;

revoke execute on function public.remove_member(uuid, uuid) from public, anon;

-- file: functions/groups/rename_group.sql
-- rename_group: commissioner renames their group (ADR-0006, dec. 4).
--
-- Enforces the same name constraints as create_group. Runs as SECURITY DEFINER so
-- it can bypass the no-client-update RLS policy on groups; the commissioner check
-- is the trust boundary.
--
-- Error codes:
--   P0001  not authenticated
--   P0010  group name is required
--   P0011  group name too long
--   P0020  caller is not a commissioner of the group
create or replace function public.rename_group(p_group_id uuid, p_name text)
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_caller_id uuid;
  v_name      text;
begin
  v_caller_id := auth.uid();

  if v_caller_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Validate name (mirrors create_group + 0221_groups_name_length.sql constraint).
  v_name := btrim(coalesce(p_name, ''));
  if length(v_name) = 0 then
    raise exception 'group name is required' using errcode = 'P0010';
  end if;
  if length(v_name) > 60 then
    raise exception 'group name too long' using errcode = 'P0011';
  end if;

  -- Caller must be a commissioner of this group.
  if not public.is_commissioner(p_group_id) then
    raise exception 'caller is not a commissioner of this group' using errcode = 'P0020';
  end if;

  update public.groups
  set name = v_name
  where id = p_group_id;
end;
$$;

revoke execute on function public.rename_group(uuid, text) from public, anon;

-- file: functions/odds/set_active_line.sql
-- supabase/functions/set_active_line.sql
create or replace function public.set_active_line(
  p_game_id        uuid,
  p_spread_team_id int,
  p_spread_value   numeric,
  p_source         text default 'fanduel'
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_home int;
  v_away int;
  v_fav  int;
  v_val  numeric;
begin
  -- Fetch home/away
  select home_team_id, away_team_id
    into v_home, v_away
  from public.games
  where id = p_game_id;

  if not found then
    raise exception 'game not found' using errcode = 'P0001';
  end if;

  if p_spread_team_id not in (v_home, v_away) then
    raise exception 'spread team id must be one of the game teams' using errcode = 'P0001';
  end if;

  if p_spread_value <= 0 then
    -- We treat negative provided value as "other team is favorite"; zero is invalid
    if p_spread_value = 0 then
      raise exception 'spread value must be non-zero' using errcode = 'P0001';
    end if;
    v_val := abs(p_spread_value);
    if p_spread_team_id = v_home then
      v_fav := v_away;
    else
      v_fav := v_home;
    end if;
  else
    v_val := p_spread_value;
    v_fav := p_spread_team_id;
  end if;

  -- Deactivate existing active line for same (game, source)
  update public.game_lines
     set is_active_line = false
   where game_id = p_game_id
     and source = p_source
     and is_active_line = true;

  -- Insert new canonical line
  insert into public.game_lines (game_id, source, spread_team_id, spread_value, is_active_line, fetched_at)
  values (p_game_id, p_source, v_fav, v_val, true, now());

  return jsonb_build_object(
    'ok', true,
    'game_id', p_game_id,
    'source', p_source,
    'spread_team_id', v_fav,
    'spread_value', v_val
  );
end
$$;

-- service_role only: set_active_line is a backend odds-sync RPC (called via the service
-- client in src/lib/server/db/commands/setActiveLine.ts), not a client RPC. A blanket
-- `revoke execute ... from authenticated` (last at migration 20260625204117) already
-- stripped the legacy authenticated grant in prod; this matches that closed-by-default
-- end state (ADR-0011) and the pgTAP negative control in tests/021.
grant execute on function public.set_active_line(uuid, int, numeric, text)
  to service_role;

-- file: functions/picks/lock_pick_all_groups.sql
create or replace function public.lock_pick_all_groups(
  p_game_id  uuid,
  p_side     public.side_enum,
  p_weight   public.weight_enum
)
returns table (
  group_id   uuid,
  ok         boolean,
  reason     text,
  locked_at  timestamptz
)
language plpgsql
security invoker
set search_path = public
as $$
#variable_conflict use_column
declare
  v_uid              uuid := auth.uid();
  v_game             public.games%rowtype;
  v_team_id          int;
  v_weeknum          int;
  v_season           int;
  v_lastwk           int;
  v_final_week_allin boolean;
  v_now              timestamptz := now();

  v_membership       record;
  v_line_source      text;
  v_line_id          int;
  v_spread_team_id   int;
  v_spread_value     numeric;
  v_row              public.picks%rowtype;
begin
  if v_uid is null then
    raise exception 'unauthorized' using errcode = 'P0001';
  end if;

  if p_side not in ('home', 'away') then
    raise exception 'invalid side' using errcode = 'P0001';
  end if;

  -- fetch game once (shared across all groups)
  select * into v_game
  from public.games
  where id = p_game_id;

  if not found then
    raise exception 'game not found' using errcode = 'P0001';
  end if;

  -- reject edits after kickoff for the whole call
  if v_now >= v_game.commence_time then
    raise exception 'edits are not allowed after kickoff' using errcode = 'P0001';
  end if;

  v_team_id := case when p_side = 'home' then v_game.home_team_id else v_game.away_team_id end;

  -- week/season/final-week flag shared across all groups
  select w.week_number, w.season_id into v_weeknum, v_season
  from public.weeks w
  where w.id = v_game.week_id;

  select max(week_number) into v_lastwk
  from public.weeks
  where season_id = v_season;

  v_final_week_allin := public._get_final_week_unlimited_allin();

  -- fan-out: one pick per active membership, skipping groups that fail individually
  for v_membership in
    select gm.group_id
    from public.group_memberships gm
    where gm.user_id = v_uid
      and gm.status  = 'active'
    order by gm.joined_at, gm.group_id
  loop
    begin
      -- resolve this group's line_source (defaults to 'fanduel' when not configured)
      select coalesce(gc.line_source, 'fanduel') into v_line_source
      from public.group_config gc
      where gc.group_id = v_membership.group_id;

      if not found then
        v_line_source := 'fanduel';
      end if;

      -- per-group All-In enforcement (mirrors lock_pick.sql:70-93)
      if p_weight = 'A' and not (v_weeknum = v_lastwk and v_final_week_allin) then
        if exists (
          select 1
          from public.picks p
          join public.games g2 on g2.id = p.game_id
          where p.group_id  = v_membership.group_id
            and p.user_id   = v_uid
            and g2.week_id  = v_game.week_id
            and p.weight    = 'A'
            and p.game_id  <> p_game_id
        ) then
          raise exception 'all in already used this week' using errcode = 'P0001';
        end if;
      end if;

      -- active line snapshot for this group's source (mirrors lock_pick.sql:96-108)
      select gl.id, gl.spread_team_id, gl.spread_value
        into v_line_id, v_spread_team_id, v_spread_value
      from public.game_lines gl
      where gl.game_id        = v_game.id
        and gl.source         = v_line_source
        and gl.is_active_line = true
      order by gl.fetched_at desc, gl.id desc
      limit 1;

      if not found then
        raise exception 'no active line for game % (source=%)', p_game_id, v_line_source
          using errcode = 'P0001';
      end if;

      -- upsert pick for this group (mirrors lock_pick.sql:110-130)
      with upsert as (
        insert into public.picks (
          group_id, user_id, game_id, picked_team_id, weight,
          locked_at, locked_by, locked_line_id, locked_spread_team_id, locked_spread_value
        )
        values (
          v_membership.group_id, v_uid, v_game.id, v_team_id, p_weight,
          v_now, v_uid, v_line_id, v_spread_team_id, v_spread_value
        )
        on conflict (group_id, user_id, game_id) do update
          set picked_team_id        = excluded.picked_team_id,
              weight                = excluded.weight,
              locked_at             = excluded.locked_at,
              locked_by             = excluded.locked_by,
              locked_line_id        = excluded.locked_line_id,
              locked_spread_team_id = excluded.locked_spread_team_id,
              locked_spread_value   = excluded.locked_spread_value
        returning *
      )
      select * into v_row from upsert;

      return query select v_membership.group_id, true, null::text, v_row.locked_at;

    exception when others then
      return query select v_membership.group_id, false, sqlerrm, null::timestamptz;
    end;
  end loop;
end
$$;

grant execute on function public.lock_pick_all_groups(uuid, public.side_enum, public.weight_enum)
  to authenticated, service_role;

-- file: functions/picks/lock_pick.sql
-- file: supabase/functions/lock_pick.sql
create or replace function public.lock_pick(
  p_game_id  uuid,
  p_side     public.side_enum,
  p_weight   public.weight_enum,
  p_source   text default 'fanduel'
)
returns table (
  ok boolean,
  user_id uuid,
  game_id uuid,
  picked_side public.side_enum,
  weight public.weight_enum,
  locked_at timestamptz
)
language plpgsql
security invoker
set search_path = public
as $$
#variable_conflict use_column
declare
  v_uid     uuid := auth.uid();
  v_game    public.games%rowtype;
  v_team_id int;
  v_weeknum int;
  v_season  int;
  v_lastwk  int;
  v_final_week_allin boolean;
  v_line_id int;
  v_spread_team_id int;
  v_spread_value numeric;
  v_now     timestamptz := now();
  v_row     public.picks%rowtype;
  v_group_id uuid;
begin
  if v_uid is null then
    raise exception 'unauthorized' using errcode = 'P0001';
  end if;

  select gm.group_id into v_group_id
  from public.group_memberships gm
  where gm.user_id = v_uid
  order by gm.joined_at, gm.group_id
  limit 1;

  if v_group_id is null then
    raise exception 'group membership not found' using errcode = 'P0001';
  end if;

  if p_side not in ('home','away') then
    raise exception 'invalid side' using errcode = 'P0001';
  end if;

  -- fetch game (no FOR UPDATE to avoid RLS "not found")
  select * into v_game
  from public.games
  where id = p_game_id;

  if not found then
    raise exception 'game not found' using errcode = 'P0001';
  end if;

  -- no edits after kickoff
  if v_now >= v_game.commence_time then
    raise exception 'edits are not allowed after kickoff' using errcode = 'P0001';
  end if;

  v_team_id := case when p_side = 'home' then v_game.home_team_id else v_game.away_team_id end;

  -- All-In (A) enforcement: once per week, unless the final-week exception is enabled
  select w.week_number, w.season_id into v_weeknum, v_season
  from public.weeks w
  where w.id = v_game.week_id;

  select max(week_number) into v_lastwk
  from public.weeks
  where season_id = v_season;

  v_final_week_allin := public._get_final_week_unlimited_allin();

  if p_weight = 'A' and not (v_weeknum = v_lastwk and v_final_week_allin) then
    if exists (
      select 1
      from public.picks p
      join public.games g2 on g2.id = p.game_id
      where p.group_id = v_group_id
        and p.user_id = v_uid
        and g2.week_id = v_game.week_id
        and p.weight = 'A'
        and p.game_id <> p_game_id
    ) then
      raise exception 'all in already used this week' using errcode = 'P0001';
    end if;
  end if;

  -- active line snapshot (required)
  select gl.id, gl.spread_team_id, gl.spread_value
    into v_line_id, v_spread_team_id, v_spread_value
  from public.game_lines gl
  where gl.game_id = v_game.id
    and gl.source  = p_source
    and gl.is_active_line = true
  order by gl.fetched_at desc, gl.id desc
  limit 1;

  if not found then
    raise exception 'no active line for game % (source=%)', p_game_id, p_source using errcode = 'P0001';
  end if;

  -- upsert with snapshot stamped atomically
  with upsert as (
    insert into public.picks (
      group_id, user_id, game_id, picked_team_id, weight,
      locked_at, locked_by, locked_line_id, locked_spread_team_id, locked_spread_value
    )
    values (
      v_group_id, v_uid, v_game.id, v_team_id, p_weight,
      v_now, v_uid, v_line_id, v_spread_team_id, v_spread_value
    )
    on conflict (group_id, user_id, game_id) do update
      set picked_team_id         = excluded.picked_team_id,
          weight                 = excluded.weight,
          locked_at              = excluded.locked_at,
          locked_by              = excluded.locked_by,
          locked_line_id         = excluded.locked_line_id,
          locked_spread_team_id  = excluded.locked_spread_team_id,
          locked_spread_value    = excluded.locked_spread_value
    returning *
  )
  select * into v_row from upsert;

  return query
  select
    true as ok,
    v_row.user_id,
    v_row.game_id,
    p_side as picked_side,
    v_row.weight,
    v_row.locked_at;
end
$$;

-- make sure the signature matches exactly (schema-qualify enums)
grant execute on function public.lock_pick(uuid, public.side_enum, public.weight_enum, text)
  to authenticated, service_role;

-- file: functions/picks/unlock_pick_all_groups.sql
create or replace function public.unlock_pick_all_groups(
  p_game_id uuid
)
returns table (
  group_id uuid,
  ok       boolean,
  reason   text
)
language plpgsql
security invoker
set search_path = public
as $$
declare
  v_uid  uuid := auth.uid();
  v_game public.games%rowtype;
  v_now  timestamptz := now();
  v_row  public.picks%rowtype;

  v_membership record;
begin
  if v_uid is null then
    raise exception 'unauthorized' using errcode = 'P0001';
  end if;

  -- fetch game (shared kickoff guard)
  select * into v_game
  from public.games
  where id = p_game_id;

  if not found then
    raise exception 'game not found' using errcode = 'P0001';
  end if;

  if game_has_started(p_game_id) or v_now >= v_game.commence_time then
    raise exception 'Edits are not allowed after kickoff' using errcode = 'P0001';
  end if;

  -- fan-out: delete pick in each active group, skip on per-group failure
  for v_membership in
    select gm.group_id
    from public.group_memberships gm
    where gm.user_id = v_uid
      and gm.status  = 'active'
    order by gm.joined_at, gm.group_id
  loop
    begin
      with del as (
        delete from public.picks p
        where p.group_id = v_membership.group_id
          and p.user_id  = v_uid
          and p.game_id  = p_game_id
        returning *
      )
      select * into v_row from del;

      if found then
        perform public.audit_log_action(
          v_uid,
          'unlock_pick_all_groups',
          jsonb_build_object(
            'group_id',              v_membership.group_id,
            'game_id',               p_game_id,
            'picked_team_id',        v_row.picked_team_id,
            'weight',                v_row.weight,
            'locked_at',             v_row.locked_at,
            'locked_line_id',        v_row.locked_line_id,
            'locked_spread_team_id', v_row.locked_spread_team_id,
            'locked_spread_value',   v_row.locked_spread_value
          )
        );
        return query select v_membership.group_id, true, null::text;
      else
        -- no pick to delete in this group; still a success (idempotent)
        return query select v_membership.group_id, true, null::text;
      end if;

    exception when others then
      return query select v_membership.group_id, false, sqlerrm;
    end;
  end loop;
end
$$;

grant execute on function public.unlock_pick_all_groups(uuid)
  to authenticated, service_role;

-- file: functions/picks/unlock_pick.sql
create or replace function public.unlock_pick(
  p_game_id uuid
)
returns table (
  ok boolean,
  user_id uuid,
  game_id uuid,
  unlocked_at timestamptz
)
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_uid  uuid := auth.uid();
  v_game public.games%rowtype;
  v_row  public.picks%rowtype;
  v_now  timestamptz := now();
  v_group_id uuid;
begin
  if v_uid is null then
    raise exception 'unauthorized' using errcode = 'P0001';
  end if;

  select gm.group_id into v_group_id
  from public.group_memberships gm
  where gm.user_id = v_uid
  order by gm.joined_at, gm.group_id
  limit 1;

  if v_group_id is null then
    raise exception 'group membership not found' using errcode = 'P0001';
  end if;

  -- Serialize against concurrent lock/unlock attempts for the same game
  select * into v_game
  from public.games
  where id = p_game_id
  for update;
  if not found then
    raise exception 'game not found' using errcode = 'P0001';
  end if;

  -- Hybrid guard: status OR scheduled kickoff time
  if game_has_started(p_game_id) or v_now >= v_game.commence_time then
    raise exception 'Edits are not allowed after kickoff' using errcode = 'P0001';
  end if;

  -- Delete the pick (if present)
  with del as (
    delete from public.picks p
    where p.group_id = v_group_id
      and p.user_id = v_uid
      and p.game_id = p_game_id
    returning *
  )
  select * into v_row from del;

  if found then
    perform public.audit_log_action(
      v_uid,
      'unlock_pick',
      jsonb_build_object(
        'game_id', p_game_id,
        'picked_team_id', v_row.picked_team_id,
        'weight', v_row.weight,
        'locked_at', v_row.locked_at,
        'locked_line_id', v_row.locked_line_id,
        'locked_spread_team_id', v_row.locked_spread_team_id,
        'locked_spread_value', v_row.locked_spread_value
      )
    );

    return query select true, v_row.user_id, v_row.game_id, v_now;
  else
    -- Nothing to delete; still record the intent (helps debug queued/offline retries)
    perform public.audit_log_action(
      v_uid,
      'unlock_pick_noop',
      jsonb_build_object('game_id', p_game_id)
    );

    return query select false, v_uid, p_game_id, v_now;
  end if;
end
$$;

revoke all on function public.unlock_pick(uuid) from public;
grant execute on function public.unlock_pick(uuid) to authenticated, service_role;

-- file: policies/10_rls_enable.sql
-- Enable RLS everywhere (deny by default)
alter table if exists public.picks       enable row level security;
alter table if exists public.pick_settlement enable row level security;
alter table if exists public.games       enable row level security;
alter table if exists public.game_lines  enable row level security;
alter table if exists public.results     enable row level security;
alter table if exists public.totals      enable row level security;
alter table if exists public.users       enable row level security;
alter table if exists public.settings    enable row level security;
alter table if exists public.audit_log   enable row level security;
alter table if exists public.weeks       enable row level security;
alter table if exists public.seasons     enable row level security;
alter table if exists public.teams       enable row level security;
alter table if exists public.groups      enable row level security;
alter table if exists public.group_memberships enable row level security;
alter table if exists public.group_config enable row level security;
alter table if exists public.group_week_overrides enable row level security;
alter table if exists public.comments  enable row level security;
alter table if exists public.reactions enable row level security;

-- file: policies/20_policies_read_core.sql
-- Core read policies (games, lines, results, totals) — readable to authenticated

drop policy if exists sel_games on public.games;
create policy sel_games
  on public.games for select
  to authenticated
  using (true);

drop policy if exists sel_game_lines on public.game_lines;
create policy sel_game_lines
  on public.game_lines for select
  to authenticated
  using (true);

drop policy if exists sel_results on public.results;
create policy sel_results
  on public.results for select
  to authenticated
  using (true);

drop policy if exists sel_totals on public.totals;
create policy sel_totals
  on public.totals for select
  to authenticated
  using (true);

-- file: policies/21_policies_read_lookup.sql
-- Lookup tables readable to authenticated (teams, weeks, seasons)

drop policy if exists sel_weeks on public.weeks;
create policy sel_weeks
  on public.weeks for select
  to authenticated
  using (true);

drop policy if exists sel_seasons on public.seasons;
create policy sel_seasons
  on public.seasons for select
  to authenticated
  using (true);

drop policy if exists sel_teams on public.teams;
create policy sel_teams
  on public.teams for select
  to authenticated
  using (true);

-- file: policies/25_policies_groups.sql
drop policy if exists sel_groups_member on public.groups;
create policy sel_groups_member
  on public.groups for select
  to authenticated
  using (public.is_member(id));

drop policy if exists ins_groups_no_client on public.groups;
create policy ins_groups_no_client
  on public.groups for insert
  to authenticated
  with check (false);

drop policy if exists upd_groups_no_client on public.groups;
create policy upd_groups_no_client
  on public.groups for update
  to authenticated
  using (false)
  with check (false);

drop policy if exists sel_group_memberships_member on public.group_memberships;
create policy sel_group_memberships_member
  on public.group_memberships for select
  to authenticated
  using (public.is_member(group_id));

-- No direct client INSERT into group_memberships. The prior member-scoped policy
-- only checked is_member(group_id), not user_id = auth.uid(), so any member could
-- insert a membership row for an arbitrary user_id. No client path needs this:
-- create_group / redeem_invite are SECURITY DEFINER and addGroupMember uses the
-- service role. Mirror groups/group_config (no-client-write); all membership writes
-- flow through SECURITY DEFINER RPCs / service role (ADR-0006).
drop policy if exists ins_group_memberships_member on public.group_memberships;
drop policy if exists ins_group_memberships_no_client on public.group_memberships;
create policy ins_group_memberships_no_client
  on public.group_memberships for insert
  to authenticated
  with check (false);

drop policy if exists upd_group_memberships_self_member on public.group_memberships;
create policy upd_group_memberships_self_member
  on public.group_memberships for update
  to authenticated
  using (public.is_member(group_id) and user_id = (select auth.uid()))
  with check (
    public.is_member(group_id)
    and user_id = (select auth.uid())
    and role = 'member'
  );

-- file: policies/26_policies_group_config.sql
-- group_config: members read their own group's config; no client writes.
drop policy if exists sel_group_config_member on public.group_config;
create policy sel_group_config_member
  on public.group_config for select
  to authenticated
  using (public.is_member(group_id));

drop policy if exists ins_group_config_no_client on public.group_config;
create policy ins_group_config_no_client
  on public.group_config for insert
  to authenticated
  with check (false);

drop policy if exists upd_group_config_no_client on public.group_config;
create policy upd_group_config_no_client
  on public.group_config for update
  to authenticated
  using (false)
  with check (false);

-- group_week_overrides: members read their own group's overrides; no client writes.
drop policy if exists sel_group_week_overrides_member on public.group_week_overrides;
create policy sel_group_week_overrides_member
  on public.group_week_overrides for select
  to authenticated
  using (public.is_member(group_id));

drop policy if exists ins_group_week_overrides_no_client on public.group_week_overrides;
create policy ins_group_week_overrides_no_client
  on public.group_week_overrides for insert
  to authenticated
  with check (false);

drop policy if exists upd_group_week_overrides_no_client on public.group_week_overrides;
create policy upd_group_week_overrides_no_client
  on public.group_week_overrides for update
  to authenticated
  using (false)
  with check (false);

-- file: policies/27_policies_group_invites.sql
-- group_invites: commissioner can manage their group's invites; no client-side redemption path.

alter table public.group_invites enable row level security;

drop policy if exists sel_group_invites_commissioner on public.group_invites;
create policy sel_group_invites_commissioner
  on public.group_invites for select
  to authenticated
  using (public.is_commissioner(group_id));

drop policy if exists ins_group_invites_commissioner on public.group_invites;
create policy ins_group_invites_commissioner
  on public.group_invites for insert
  to authenticated
  with check (
    public.is_commissioner(group_id)
    and created_by = (select auth.uid())
  );

drop policy if exists upd_group_invites_commissioner on public.group_invites;
create policy upd_group_invites_commissioner
  on public.group_invites for update
  to authenticated
  using (public.is_commissioner(group_id))
  with check (public.is_commissioner(group_id));

drop policy if exists del_group_invites_no_client on public.group_invites;
create policy del_group_invites_no_client
  on public.group_invites for delete
  to authenticated
  using (false);

-- file: policies/30_policies_users.sql
-- Users: everyone can read; each user may update their own display_name

drop policy if exists sel_users on public.users;
create policy sel_users
  on public.users for select
  to authenticated
  using (true);

drop policy if exists upd_users_self on public.users;
create policy upd_users_self
  on public.users for update
  to authenticated
  using (id = auth.uid())
  with check (id = auth.uid());

drop policy if exists ins_audit_by_actor on public.audit_log;
create policy ins_audit_by_actor
on public.audit_log
for insert
to authenticated
with check (actor = auth.uid());

-- file: policies/40_policies_picks.sql
-- Picks: owner-only before kickoff for writes; reveal after kickoff for reads
-- Requires helper functions: public.game_has_started(uuid)

drop policy if exists sel_picks_owner_or_started on public.picks;
create policy sel_picks_owner_or_started
  on public.picks for select
  to authenticated
  using (
    public.is_member(group_id)
    and (user_id = (select auth.uid()) or public.game_has_started(game_id))
  );

drop policy if exists ins_picks_own_pre on public.picks;
create policy ins_picks_own_pre
  on public.picks for insert
  to authenticated
  with check (
    public.is_member(group_id)
    and user_id = (select auth.uid())
    and not public.game_has_started(game_id)
  );

drop policy if exists upd_picks_pre on public.picks;
create policy upd_picks_pre
  on public.picks for update
  to authenticated
  using (
    public.is_member(group_id)
    and user_id = (select auth.uid())
    and not public.game_has_started(game_id)
  )
  with check (
    public.is_member(group_id)
    and user_id = (select auth.uid())
    and not public.game_has_started(game_id)
  );

-- Delete own pre-kickoff picks (required for unlock_pick_all_groups SECURITY INVOKER).
-- Mirrors the update guard: member, own row, before kickoff only.
drop policy if exists del_picks_own_pre on public.picks;
create policy del_picks_own_pre
  on public.picks for delete
  to authenticated
  using (
    public.is_member(group_id)
    and user_id = (select auth.uid())
    and not public.game_has_started(game_id)
  );

-- file: policies/41_policies_comments_reactions.sql
-- Comments: members may post anytime; reads are gated to post-kickoff to avoid
-- revealing pick context before the game locks (mirrors the picks read gate in
-- 40_policies_picks.sql).

drop policy if exists sel_comments_member_post_kickoff on public.comments;
create policy sel_comments_member_post_kickoff
  on public.comments for select
  to authenticated
  using (
    public.is_member(group_id)
    and public.game_has_started(game_id)
    and deleted_at is null
  );

drop policy if exists ins_comments_own_member on public.comments;
create policy ins_comments_own_member
  on public.comments for insert
  to authenticated
  with check (
    public.is_member(group_id)
    and user_id = (select auth.uid())
  );

drop policy if exists del_comments_own on public.comments;
create policy del_comments_own
  on public.comments for delete
  to authenticated
  using (
    public.is_member(group_id)
    and user_id = (select auth.uid())
  );

-- Reactions: same post-kickoff read gate; toggle (insert + delete) allowed for members.

drop policy if exists sel_reactions_member_post_kickoff on public.reactions;
create policy sel_reactions_member_post_kickoff
  on public.reactions for select
  to authenticated
  using (
    public.is_member(group_id)
    and public.game_has_started(game_id)
  );

drop policy if exists ins_reactions_own_member on public.reactions;
create policy ins_reactions_own_member
  on public.reactions for insert
  to authenticated
  with check (
    public.is_member(group_id)
    and user_id = (select auth.uid())
  );

drop policy if exists del_reactions_own on public.reactions;
create policy del_reactions_own
  on public.reactions for delete
  to authenticated
  using (
    public.is_member(group_id)
    and user_id = (select auth.uid())
  );

-- file: policies/45_policies_push_notifications.sql
-- push_subscriptions: owners manage only their own rows.
drop policy if exists sel_own_push_subscriptions on public.push_subscriptions;
create policy sel_own_push_subscriptions
  on public.push_subscriptions for select
  to authenticated
  using (user_id = auth.uid());

drop policy if exists ins_own_push_subscriptions on public.push_subscriptions;
create policy ins_own_push_subscriptions
  on public.push_subscriptions for insert
  to authenticated
  with check (user_id = auth.uid());

drop policy if exists upd_own_push_subscriptions on public.push_subscriptions;
create policy upd_own_push_subscriptions
  on public.push_subscriptions for update
  to authenticated
  using (user_id = auth.uid())
  with check (user_id = auth.uid());

drop policy if exists del_own_push_subscriptions on public.push_subscriptions;
create policy del_own_push_subscriptions
  on public.push_subscriptions for delete
  to authenticated
  using (user_id = auth.uid());

-- notification_log: owners may read their own rows; all writes go through the
-- service role (which bypasses RLS).
drop policy if exists sel_own_notification_log on public.notification_log;
create policy sel_own_notification_log
  on public.notification_log for select
  to authenticated
  using (user_id = auth.uid());

-- file: policies/50_policies_admin.sql
-- Settings & audit: admin-only (via public.is_admin())

drop policy if exists admin_sel_settings on public.settings;
create policy admin_sel_settings
  on public.settings for select
  to authenticated
  using (public.is_admin());

drop policy if exists admin_all_settings on public.settings;
create policy admin_all_settings
  on public.settings for all
  to authenticated
  using (public.is_admin())
  with check (public.is_admin());

drop policy if exists admin_sel_audit on public.audit_log;
create policy admin_sel_audit
  on public.audit_log for select
  to authenticated
  using (public.is_admin());

drop policy if exists admin_ins_audit on public.audit_log;
create policy admin_ins_audit
  on public.audit_log for insert
  to authenticated
  with check (public.is_admin());

drop policy if exists admin_sel_cron_run_log on public.cron_run_log;
create policy admin_sel_cron_run_log
  on public.cron_run_log for select
  to authenticated
  using (public.is_admin());

-- file: grants/admin_grants.sql
-- =========================
-- ADMIN (JWT claim role=admin)
-- =========================
-- No separate DB role for "admin"; it's a claim checked by RLS/functions.
-- Admin-only behavior is enforced by:
--   - RLS USING/WITH CHECK (is_admin())
--   - Admin RPCs that call is_admin() and raise on non-admins

-- =========================
-- SERVICE ROLE (server-side key; bypasses RLS)
-- =========================
-- Full, explicit privileges for backend tasks and admin RPC execution.

grant usage on schema public to service_role;

grant select, insert, update, delete, truncate, references, trigger
  on all tables in schema public to service_role;

grant usage, select on all sequences in schema public to service_role;
grant execute on all functions in schema public to service_role;

-- Keep future objects service-ready
alter default privileges in schema public
  grant select, insert, update, delete, truncate, references, trigger on tables to service_role;

alter default privileges in schema public
  grant usage, select on sequences to service_role;

alter default privileges in schema public
  grant execute on functions to service_role;

-- Optional: if you prefer admin RPCs callable ONLY by backend,
-- don't grant EXECUTE to 'authenticated' for those RPCs at all.
-- Call them from your API route with the service key.

-- file: grants/anon_grants.sql
-- =========================
-- ANON (not signed in)
-- =========================

-- Schema resolve only; no data by default
grant usage on schema public to anon;

-- Don’t let anon call any RPCs by default
revoke execute on all functions in schema public from anon;
alter default privileges in schema public revoke execute on functions from anon;

-- Enums: anon doesn't need to pass these into RPCs
revoke usage on type public.weight_enum from anon;
revoke usage on type public.side_enum  from anon;

-- If you later add anon-safe read RPCs, grant EXECUTE in those function files.
-- If you add an anon RLS policy to read games/lines directly, you’ll also need:
--   grant select on public.games, public.game_lines to anon;
-- but with current RLS (authenticated-only), that grant would have no effect.

-- file: grants/group_grants.sql
-- groups / group_memberships: authenticated access is gated by RLS.
-- Strip default public/anon ACLs first so anon has no Data API access.
revoke all on public.groups from public, anon;
revoke all on public.group_memberships from public, anon;

grant select on public.groups to authenticated;
-- SELECT only: all membership writes go through SECURITY DEFINER RPCs / service role.
-- Direct client INSERT is blocked by the no-client-write policy (25_policies_groups.sql).
grant select on public.group_memberships to authenticated;

grant execute on function public.is_member(uuid) to authenticated, service_role;

-- create_group is the only insert path into groups (RLS blocks direct client
-- inserts). It is SECURITY DEFINER and enforces the create-gate internally.
grant execute on function public.create_group(text) to authenticated, service_role;

-- Commissioner management RPCs (ADR-0006, dec. 4 + 5): SECURITY DEFINER, caller-trust
-- verified internally; no direct client writes to groups.name or group_memberships.role.
grant execute on function public.rename_group(uuid, text)  to authenticated, service_role;
grant execute on function public.remove_member(uuid, uuid) to authenticated, service_role;
grant execute on function public.promote_member(uuid, uuid) to authenticated, service_role;
grant execute on function public.leave_group(uuid)         to authenticated, service_role;
grant execute on function public.mint_invite(uuid, integer, timestamptz) to authenticated, service_role;

-- group_config / group_week_overrides: authenticated read gated by RLS.
-- Client writes are blocked by policy; all writes go through service_role.
revoke all on public.group_config from public, anon;
revoke all on public.group_week_overrides from public, anon;

grant select on public.group_config to authenticated;
grant select on public.group_week_overrides to authenticated;

-- group_invites: commissioners manage invites, gated by RLS; no anon access.
revoke all on public.group_invites from public, anon;

grant select, insert, update on public.group_invites to authenticated;

grant execute on function public.is_commissioner(uuid) to authenticated, service_role;
grant execute on function public.redeem_invite(text) to authenticated, service_role;
-- preview_invite: read-only display state for /join/[code]; SECURITY DEFINER so
-- invitees can preview an invite the commissioner-only RLS would otherwise hide.
grant execute on function public.preview_invite(text) to authenticated, service_role;

-- comments / reactions: members read+write their group's rows, gated by RLS.
-- Strip default anon/public ACLs first (defense in depth alongside RLS).
revoke all on public.comments  from public, anon;
revoke all on public.reactions from public, anon;

grant select, insert, delete on public.comments  to authenticated;
grant select, insert, delete on public.reactions to authenticated;

-- file: grants/picks_fanout_grants.sql
-- Grants for the global-picks write-time fan-out (issue #214).
--
-- These live in their own grants-phase file (rather than in player_grants.sql) so a
-- fan-out change never has to touch the core player grants. Under the closed-by-default
-- baseline (ADR-0011) there is no blanket revoke to outrun, so order among grant files
-- no longer matters -- this file used to be `zz_`-prefixed purely to sort after
-- player_grants.sql; the ADR-0012 rebaseline removed that ordering hack.

-- DELETE on picks: unlock_pick_all_groups is SECURITY INVOKER, so the caller's role
-- (authenticated) must hold DELETE for the del_picks_own_pre RLS policy to apply.
-- (player_grants.sql grants SELECT/INSERT/UPDATE; DELETE is added here.)
grant delete on public.picks to authenticated;

-- Fan-out RPCs: SECURITY INVOKER, so RLS enforces per-group write permission.
grant execute on function public.lock_pick_all_groups(uuid, public.side_enum, public.weight_enum)
  to authenticated, service_role;
grant execute on function public.unlock_pick_all_groups(uuid)
  to authenticated, service_role;

-- audit_log_action is SECURITY DEFINER but is CALLED by unlock_pick_all_groups while
-- it runs as authenticated (INVOKER), so authenticated needs EXECUTE on it. The old
-- unlock_pick is SECURITY DEFINER and never needed this; the fan-out variant does.
grant execute on function public.audit_log_action(uuid, text, jsonb)
  to authenticated, service_role;

-- file: grants/player_grants.sql
-- =========================
-- PLAYER (authenticated, non-admin)
-- =========================

-- Basic resolution (also granted by the closed-by-default baseline; restated here so
-- this file reads on its own).
grant usage on schema public to authenticated;

-- NOTE: function access starts closed in schemas/0001_role_baseline.sql, which revokes
-- EXECUTE from PUBLIC (the implicit grant authenticated actually rode) and sets the
-- born-closed default for future functions. There is intentionally no blanket
-- `revoke execute ... from authenticated` here: it never closed the real door (PUBLIC
-- did), and -- because this file is emitted in the grants phase, after the functions
-- phase -- it would strip the explicit per-function grants made in the function source
-- files (the closure helpers, get-only RPCs, etc.). Each function re-opens itself.

-- Enums used by player RPCs
grant usage on type public.weight_enum to authenticated;
grant usage on type public.side_enum  to authenticated;

-- Defense in depth: strip Supabase's default anon/PUBLIC ACL on every table that has
-- no anon RLS policy. Supabase auto-grants ALL on new public tables to anon/PUBLIC;
-- RLS already blocks rows, but revoking the grant closes Data API reachability too
-- (the same revoke-before-grant pattern already applied to cron_run_log /
-- push_subscriptions / notification_log below and the group-owned tables). Runs before
-- the explicit `authenticated` grants below, which survive (revoke targets only
-- anon/PUBLIC); service_role keeps access via admin_grants.sql.
revoke all on
  public.games, public.game_lines, public.results, public.totals,
  public.users, public.weeks, public.seasons, public.teams,
  public.picks, public.pick_settlement, public.settings, public.audit_log
from public, anon;

-- Base table privileges (RLS still enforces row/column rules)
grant select on public.games,
               public.game_lines,
               public.results,
               public.totals,
               public.users,
               public.weeks,
               public.seasons,
               public.teams
to authenticated;

-- Picks CRUD the player needs; RLS gates who/when
grant select, insert, update on public.picks to authenticated;
grant select on public.pick_settlement to authenticated;

-- Settings & audit:
-- Grant SELECT so admins (who are also 'authenticated') can read via RLS (is_admin()).
-- Do NOT grant write widely; writes happen via SECURITY DEFINER admin RPCs.
grant select on public.settings, public.audit_log to authenticated;

-- cron_run_log: admin-only reads via RLS (is_admin()); writes come from service role.
-- Supabase's default ACL auto-grants ALL on new public tables to anon/authenticated,
-- so strip anon (and PUBLIC) first -- defense in depth alongside RLS, mirroring the
-- revoke/grant pattern on public.picks_status_view_user. authenticated keeps SELECT,
-- gated to admins by the admin_sel_cron_run_log policy.
revoke all on public.cron_run_log from public, anon;
grant select on public.cron_run_log to authenticated;

-- push_subscriptions: owners manage their own rows; RLS gates which rows.
-- Strip the default anon/PUBLIC ACL first (defense in depth alongside RLS).
revoke all on public.push_subscriptions from public, anon;
grant select, insert, update, delete on public.push_subscriptions to authenticated;

-- notification_log: owners read their own rows via RLS; writes come from service role.
revoke all on public.notification_log from public, anon;
grant select on public.notification_log to authenticated;

-- Player-facing RPCs whose source files do not append their own grant. The baseline
-- revokes EXECUTE from PUBLIC, so these explicit grants are the sole path for
-- authenticated. lock_pick/unlock_pick/is_member live here (rather than self-granting in
-- their function files) by long-standing convention; keep them co-located.
grant execute on function public.lock_pick(uuid, public.side_enum, public.weight_enum, text)
  to authenticated, service_role;
grant execute on function public.unlock_pick(uuid)
  to authenticated, service_role;
grant execute on function public.is_member(uuid)
  to authenticated, service_role;

-- NOTE: The remaining RPCs follow the convention of appending their own EXECUTE
-- grants in their own source files:
--   - public get-only RPCs (e.g., get_active_week_games): GRANT to anon, authenticated
--   - admin RPCs: handled via service_role or guarded is_admin() (see admin_grants.sql)
